sql:
SELECT claim_id, submission_date 
FROM claims 
ORDER BY submission_date DESC;

SELECT claim_text
FROM claims
WHERE fact_check_agency_id IS NOT NULL;

external_knowledge:
- 'fact-checking agencies' are organizations that verify the accuracy of claims; 
- 'users' are individuals who submit claims for verification;
- 'status' refers to the verification status of a claim, indicating whether it has been verified, debunked, or is still pending review.

sql:
SELECT claim_text
FROM claims
WHERE fact_check_agency_id IS NOT NULL;
